import { unstable_cache } from "next/cache";

export interface Post {
  id: string;
  title: string;
  content: string;
  createdAt: string;
}

// In-memory post store (in a real app, this would be a database)
const _posts: Post[] = [
  {
    id: "1",
    title: "First Post",
    content: "Welcome to the blog!",
    createdAt: new Date("2026-01-01").toISOString(),
  },
  {
    id: "2",
    title: "Next.js is Awesome",
    content: "Server Actions and cache tags make data fetching a breeze.",
    createdAt: new Date("2026-06-15").toISOString(),
  },
];

let nextId = 3;

/**
 * Fetch all posts, with caching tagged as "posts".
 *
 * The returned data is cached in Next.js's Data Cache under the "posts" tag.
 * When the cache is invalidated (via revalidateTag("posts")), the next call
 * runs this function again to fetch fresh data.
 */
export const getPosts = unstable_cache(
  async () => {
    // Simulate a data-fetching delay so cache hits/vs misses are observable
    await new Promise((resolve) => setTimeout(resolve, 300));
    return [..._posts];
  },
  ["posts-list"],
  { tags: ["posts"] }
);

/**
 * Create a new post and add it to the store.
 *
 * NOTE: After calling this, the caller should also call
 * `revalidateTag("posts")` so the page re-renders with the new post.
 */
export async function createPostInStore(data: {
  title: string;
  content: string;
}): Promise<Post> {
  const post: Post = {
    id: String(nextId++),
    title: data.title,
    content: data.content,
    createdAt: new Date().toISOString(),
  };
  _posts.push(post);
  return post;
}

"use server";

import { revalidateTag } from "next/cache";
import { createPostInStore } from "@/lib/posts";

/**
 * Server Action that creates a new post and invalidates the "posts" cache tag.
 *
 * After the action runs, Next.js will re-render the page. Because
 * `revalidateTag("posts")` purges the Data Cache entries tagged "posts",
 * the re-render will fetch fresh data rather than serving stale cached content.
 */
export async function createPost(formData: FormData) {
  const title = formData.get("title");
  const content = formData.get("content");

  if (
    typeof title !== "string" ||
    title.trim().length === 0 ||
    typeof content !== "string" ||
    content.trim().length === 0
  ) {
    throw new Error("Title and content are required");
  }

  await createPostInStore({ title: title.trim(), content: content.trim() });

  // Invalidate all cached data tagged with "posts".
  // This guarantees the next page render fetches fresh data from the store ŌĆö
  // stale cached content will NOT be served.
  revalidateTag("posts");
}

import { getPosts } from "@/lib/posts";
import { createPost } from "./actions";

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ maxWidth: 640, margin: "0 auto", padding: 24 }}>
      <h1>Posts</h1>

      {/* Posts list */}
      {posts.length === 0 ? (
        <p>No posts yet. Create one below!</p>
      ) : (
        <ul style={{ listStyle: "none", padding: 0 }}>
          {posts.map((post) => (
            <li
              key={post.id}
              style={{
                border: "1px solid #ddd",
                borderRadius: 8,
                padding: "12px 16px",
                marginBottom: 12,
              }}
            >
              <h2 style={{ marginTop: 0, marginBottom: 4 }}>{post.title}</h2>
              <p style={{ margin: "4px 0" }}>{post.content}</p>
              <time
                style={{ fontSize: "0.8rem", color: "#666" }}
              >
                {new Date(post.createdAt).toLocaleDateString("en-US", {
                  year: "numeric",
                  month: "long",
                  day: "numeric",
                })}
              </time>
            </li>
          ))}
        </ul>
      )}

      <hr style={{ margin: "24px 0" }} />

      {/* Create-post form ŌĆö submits to the Server Action */}
      <form action={createPost}>
        <div style={{ marginBottom: 12 }}>
          <label htmlFor="title" style={{ display: "block", marginBottom: 4 }}>
            Title
          </label>
          <input
            id="title"
            name="title"
            placeholder="Enter post title"
            required
            style={{ width: "100%", padding: "8px 12px" }}
          />
        </div>

        <div style={{ marginBottom: 12 }}>
          <label
            htmlFor="content"
            style={{ display: "block", marginBottom: 4 }}
          >
            Content
          </label>
          <textarea
            id="content"
            name="content"
            placeholder="Enter post content"
            required
            rows={4}
            style={{ width: "100%", padding: "8px 12px" }}
          />
        </div>

        <button
          type="submit"
          style={{
            padding: "10px 20px",
            backgroundColor: "#0070f3",
            color: "#fff",
            border: "none",
            borderRadius: 6,
            cursor: "pointer",
          }}
        >
          Create Post
        </button>
      </form>
    </main>
  );
}

